import anthropic
import base64
from pathlib import Path

client = anthropic.Anthropic()

def analyze_pdf(pdf_path: str, question: str) -> str:
    """Send a PDF file to Claude and ask a question about it."""
    pdf_data = Path(pdf_path).read_bytes()
    pdf_b64 = base64.standard_b64encode(pdf_data).decode("utf-8")

    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=2048,
        messages=[
            {
                "role": "user",
                "content": [
                    {
                        "type": "document",
                        "source": {
                            "type": "base64",
                            "media_type": "application/pdf",
                            "data": pdf_b64
                        }
                    },
                    {
                        "type": "text",
                        "text": question
                    }
                ]
            }
        ]
    )
    return response.content[0].text

# Single question
result = analyze_pdf("annual_report_2024.pdf",
                     "What was the total revenue in Q4? Provide the exact figure from the document.")

# Multiple questions about the same PDF
def analyze_pdf_multiple(pdf_path: str, questions: list[str]) -> list[str]:
    """Analyze a PDF with multiple questions efficiently using caching."""
    pdf_data = Path(pdf_path).read_bytes()
    pdf_b64 = base64.standard_b64encode(pdf_data).decode("utf-8")

    # The PDF document block with cache_control
    doc_block = {
        "type": "document",
        "source": {
            "type": "base64",
            "media_type": "application/pdf",
            "data": pdf_b64
        },
        "cache_control": {"type": "ephemeral"}  # Cache the PDF processing
    }

    results = []
    for question in questions:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            messages=[
                {
                    "role": "user",
                    "content": [doc_block, {"type": "text", "text": question}]
                }
            ]
        )
        results.append(response.content[0].text)

    return results

import anthropic
import base64
from pypdf import PdfReader, PdfWriter
from pathlib import Path
import io

client = anthropic.Anthropic()

def split_pdf_by_pages(pdf_path: str, chunk_size: int = 50) -> list[bytes]:
    """Split a large PDF into chunks of chunk_size pages each."""
    reader = PdfReader(pdf_path)
    total_pages = len(reader.pages)
    chunks = []

    for start in range(0, total_pages, chunk_size):
        writer = PdfWriter()
        end = min(start + chunk_size, total_pages)
        for i in range(start, end):
            writer.add_page(reader.pages[i])
        buffer = io.BytesIO()
        writer.write(buffer)
        chunks.append(buffer.getvalue())

    return chunks

def analyze_large_pdf(pdf_path: str, question: str) -> str:
    """
    Analyze a large PDF by splitting it into chunks and
    synthesizing answers across chunks.
    """
    chunks = split_pdf_by_pages(pdf_path, chunk_size=80)

    if len(chunks) == 1:
        return analyze_pdf(pdf_path, question)

    # Get answer from each chunk
    chunk_answers = []
    for i, chunk_bytes in enumerate(chunks):
        chunk_b64 = base64.standard_b64encode(chunk_bytes).decode("utf-8")
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            messages=[{
                "role": "user",
                "content": [
                    {
                        "type": "document",
                        "source": {"type": "base64", "media_type": "application/pdf",
                                   "data": chunk_b64}
                    },
                    {
                        "type": "text",
                        "text": (
                            f"This is chunk {i+1} of {len(chunks)} from a larger document. "
                            f"Answer this question based only on this chunk, "
                            f"or say NOT_IN_CHUNK if the answer is not here:\n{question}"
                        )
                    }
                ]
            }]
        )
        answer = response.content[0].text
        if "NOT_IN_CHUNK" not in answer:
            chunk_answers.append(f"[Chunk {i+1}]: {answer}")

    if not chunk_answers:
        return "The answer was not found in any section of the document."

    # Synthesize across chunks
    synthesis_response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        messages=[{
            "role": "user",
            "content": (
                f"Synthesize these answers from different sections of a document into one coherent response.\n"
                f"Question: {question}\n\n"
                + "\n\n".join(chunk_answers)
            )
        }]
    )
    return synthesis_response.content[0].text
